update fr_annotation_${sequenceNumber}
area = #{area}, perimeter = #{perimeter}, category_id = #{categoryId}, description = #{description}, location_type = #{locationType}, annotation_type = #{annotationType},
update_by = #{updateBy}, structure_id = #{structureId}, structure_size = #{structureSize}, id = #{id}, update_time = now()
