mapper.insert:
CREATE TABLE "public".fr_annotation_${sequenceNumber} (
                                                          "annotation_id" int8 NOT NULL DEFAULT nextval('fr_annotation_${sequenceNumber}_annotation_id_seq'::regclass),
                                                          "area" VARCHAR ( 50 ) COLLATE"pg_catalog"."default",
                                                          "perimeter" VARCHAR ( 50 ) COLLATE"pg_catalog"."default",
                                                          "description" VARCHAR ( 100 ) COLLATE"pg_catalog"."default",
                                                          "category_id" INT8,
                                                          "contour625" geometry ( GEOMETRY ),
                                                          "contour2500" geometry ( GEOMETRY ),
                                                          "contour10000" geometry ( GEOMETRY ),
                                                          "contour40000" geometry ( GEOMETRY ),
                                                          "location_type" VARCHAR ( 100 ) COLLATE"pg_catalog"."default",
                                                          "annotation_type" VARCHAR ( 50 ) COLLATE"pg_catalog"."default",
                                                          "create_by" INT8,
                                                          "create_time" DATE,
                                                          "update_by" INT8,
                                                          "update_time" DATE,
                                                          "project_id" INT8,
                                                          "slide_id" INT8,
                                                          "structure_id" VARCHAR ( 50 ) COLLATE"pg_catalog"."default",
                                                          "structure_size" INT2,
                                                          "review_round_id" INT8,
                                                          "id" VARCHAR ( 500 ) COLLATE"pg_catalog"."default",
                                                          CONSTRAINT "fr_annotation_${sequenceNumber}_pkey" PRIMARY KEY ( "annotation_id" )
);


ALTER TABLE"fr_annotation_${sequenceNumber}" OWNER TO "postgres";

CREATE INDEX "fr_annotation_${sequenceNumber}_project_id_idx" ON "public"."fr_annotation_${sequenceNumber}" USING btree (
    "project_id" "pg_catalog"."int8_ops" ASC NULLS LAST
    );

CREATE INDEX "fr_annotation_${sequenceNumber}_slide_id_idx" ON "public"."fr_annotation_${sequenceNumber}" USING btree (
    "slide_id" "pg_catalog"."int8_ops" ASC NULLS LAST
    );

CREATE INDEX "fr_annotation_${sequenceNumber}_contour40000_idx" ON "public"."fr_annotation_${sequenceNumber}" USING gist (
    "contour40000" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_annotation_${sequenceNumber}_contour625_idx" ON "public"."fr_annotation_${sequenceNumber}" USING gist (
    "contour625" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_annotation_${sequenceNumber}_contour2500_idx" ON "public"."fr_annotation_${sequenceNumber}" USING gist (
    "contour2500" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_annotation_${sequenceNumber}_contour10000_idx" ON "public"."fr_annotation_${sequenceNumber}" USING gist (
    "contour10000" "public"."gist_geometry_ops_2d"
    );

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."annotation_id" IS '主键id';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."area" IS '面积';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."perimeter" IS '周长';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."description" IS '轮廓描述';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."category_id" IS '轮廓标签id';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."contour40000" IS '轮廓坐标';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."contour625" IS '轮廓坐标625';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."contour2500" IS '轮廓坐标2500';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."contour10000" IS '轮廓坐标10000';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."location_type" IS '轮廓类型';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."annotation_type" IS '标注类型(AI表示AI算出的标注，Draw表示前端绘制的标注)';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."create_by" IS '标注创建者';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."create_time" IS '创建时间';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."update_by" IS '更新者';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."update_time" IS '更新时间';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."project_id" IS '项目id';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."slide_id" IS '切片id';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."structure_id" IS '结构ID';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."structure_size" IS '结构大小';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."review_round_id" IS '轮次id';

COMMENT ON COLUMN "public"."fr_annotation_${sequenceNumber}"."id" IS 'geojson中数据id';

mapper.select:
select annotation_id, area, perimeter, description, category_id, location_type, annotation_type, create_by, create_time, update_by, update_time, project_id, slide_id, structure_id, structure_size, review_round_id,123123 id, ST_AsGeoJSON(st_setsrid(contour${magnification},4327)) as contour from fr_annotation_${sequenceNumber} where slide_id = #{slideId}
AND create_by = #{createBy}
AND ST_Intersects(ST_SetSRID(st_geomfromgeojson(#{contour}),4327),st_setsrid(contour${magnification},4327))
AND annotation_type = #{annotationType}
AND structure_size in
#{structureSize}
AND category_id = 0

select annotation_id, area, perimeter, description, category_id, location_type, annotation_type, create_by, create_time, update_by, update_time, project_id, slide_id, structure_id, structure_size, review_round_id, id, ST_AsGeoJSON(LOCATION) AS LOCATION from fr_annotation_${sequenceNumber}
annotation_id in
#{annotationId,jdbcType=BIGINT}

SELECT category_id
FROM fr_annotation_${sequenceNumber}
WHERE slide_id = #{slideId}
  AND category_id != 0
GROUP BY category_id
